# Harbor Fullscreen Patch - instalador independente de arquivo unico
# Uso remoto: iwr -useb <URL-DESTE-ARQUIVO> | iex
param(
    [string]$DiscordRoot = (Join-Path $env:LOCALAPPDATA 'Discord'),
    [string]$InstallRoot = (Join-Path $env:APPDATA 'HarborFullscreenPatch')
)

$ErrorActionPreference = 'Stop'
$MpvDownloadUrl = 'https://github.com/mpv-player/mpv/releases/download/git-release/mpv-v0.41.0-dev-g94335ab87-29360976857-x86_64-pc-windows-msvc.zip'
$MpvSha256 = 'AE329F16BCD9CF6C9F86D64E7977F957FB3FDAA2527451572F55C2039A369BFF'

$discordWasRunning = [bool](Get-Process -Name Discord -ErrorAction SilentlyContinue)
Write-Host '[1/3] Fechando o Discord...'
if ($discordWasRunning) {
    1..25 | ForEach-Object {
        Get-Process -Name Discord -ErrorAction SilentlyContinue |
            Stop-Process -Force -ErrorAction SilentlyContinue
        Start-Sleep -Milliseconds 200
    }
}
if (Get-Process -Name Discord -ErrorAction SilentlyContinue) {
    throw 'O Discord nao pode ser encerrado. Execute o PowerShell como administrador e tente novamente.'
}

$payloadBase64 = ''
$payloadJson = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($payloadBase64))
$payload = $payloadJson | ConvertFrom-Json
$utf8NoBom = New-Object Text.UTF8Encoding($false)

Write-Host '[2/3] Instalando o patch...'
New-Item -ItemType Directory -Force -Path $InstallRoot | Out-Null
$mpvDir = Join-Path $InstallRoot 'mpv'
$mpvExe = Join-Path $mpvDir 'mpv.exe'
if (-not (Test-Path -LiteralPath $mpvExe -PathType Leaf)) {
    $mpvZip = Join-Path $env:TEMP 'harbor-mpv-audio.zip'
    Write-Host 'Baixando o MPV oficial para o audio...'
    try {
        Invoke-WebRequest -UseBasicParsing -Uri $MpvDownloadUrl -OutFile $mpvZip
        $downloadedHash = (Get-FileHash -LiteralPath $mpvZip -Algorithm SHA256).Hash
        if ($downloadedHash -ne $MpvSha256) {
            throw "Falha de seguranca: SHA-256 do MPV invalido ($downloadedHash)."
        }
        if (Test-Path -LiteralPath $mpvDir) {
            Remove-Item -LiteralPath $mpvDir -Recurse -Force
        }
        New-Item -ItemType Directory -Force -Path $mpvDir | Out-Null
        Expand-Archive -LiteralPath $mpvZip -DestinationPath $mpvDir -Force
        if (-not (Test-Path -LiteralPath $mpvExe -PathType Leaf)) {
            throw 'O pacote do MPV nao contem mpv.exe.'
        }
    } finally {
        Remove-Item -LiteralPath $mpvZip -Force -ErrorAction SilentlyContinue
    }
}
# Remove componentes de versoes antigas; o patch atual concede apenas fullscreen.
Remove-Item -LiteralPath (Join-Path $InstallRoot 'activity-patch.js') -Force -ErrorAction SilentlyContinue
foreach ($property in $payload.PSObject.Properties) {
    $destination = Join-Path $InstallRoot $property.Name
    [IO.File]::WriteAllText($destination, [string]$property.Value, $utf8NoBom)
}

. (Join-Path $InstallRoot 'patch-common.ps1')
$apps = @(Get-HarborDiscordApps -DiscordRoot $DiscordRoot | Where-Object {
    $resources = Join-Path $_.FullName 'resources'
    (Test-Path -LiteralPath (Join-Path $resources 'app.asar')) -or
        (Test-Path -LiteralPath (Join-Path $resources '_app.asar') -PathType Leaf)
})
if ($apps.Count -eq 0) {
    throw "Nenhuma instalacao completa do Discord encontrada em $DiscordRoot. Aguarde a atualizacao terminar e tente novamente."
}

$patcher = Join-Path $InstallRoot 'patcher.js'
$installed = Install-HarborPatchIntoApp -AppDir $apps[0].FullName -PatcherPath $patcher 6>$null
if (-not $installed) {
    throw 'Nao foi possivel instalar na versao mais recente do Discord. Veja os avisos acima.'
}

$runKey = 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Run'
$repair = Join-Path $InstallRoot 'repair.ps1'
$runCommand = "powershell.exe -NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File `"$repair`""
New-Item -Path $runKey -Force | Out-Null
Set-ItemProperty -Path $runKey -Name 'HarborFullscreenPatchRepair' -Value $runCommand

$discordExe = Join-Path $apps[0].FullName 'Discord.exe'
if (Test-Path -LiteralPath $discordExe -PathType Leaf) {
    Write-Host '[3/3] Abrindo o Discord...'
    Start-Process -FilePath $discordExe -RedirectStandardOutput 'NUL' -RedirectStandardError '\\.\NUL'
}

Write-Host 'Finalizado.' -ForegroundColor Green
Start-Sleep -Milliseconds 800
exit 0
